import { isCategoricalDomain, isMinMaxDomain } from './is-value-domain.js';
import { SCALE_FALLBACK_COLOR } from '../../core/constants.js';
import {
  isColoredRangeArray,
  type ColoredRange,
} from '../../core/types/colored-range.js';
import type { MinMax } from '../../core/types/min-max.js';
import { buildCategoricalColorScale } from '../../core/utils/build-categorical-color-scale.js';
import { buildQuantizeScaleFromColorPalette } from '../../core/utils/build-quantize-scale-from-color-palette.js';
import { buildThresholdScaleFromRanges } from '../../core/utils/build-threshold-scale-from-ranges.js';
import { safeGet } from '../../core/utils/safe-get.js';
import { DEFAULT_COLOR_PALETTE_RECT } from '../constants/defaults.js';
import type {
  RectSeriesWithDatapoints,
  SeriesId,
  RectSeriesIdToValueScaleDomain,
  XYChartColorScale,
  RectSeriesToMetadata,
} from '../types/xy-chart-internals.js';

const fitColorRangeToMinMax = (
  coloredRange: ColoredRange,
  limits: Partial<MinMax>,
) => {
  const { from, to } = coloredRange;
  const { min, max } = limits;

  const isOutOfBounds =
    (max !== undefined && from > max) || (min !== undefined && to < min);

  const returnObject = coloredRange;

  if (isOutOfBounds) {
    return null;
  }
  if (max !== undefined && max < to) {
    returnObject.to = max;
  }
  if (min !== undefined && min > from) {
    returnObject.from = min;
  }
  return returnObject;
};

const fitColorRangePaletteToMinMax = (
  colorPalette: ColoredRange[],
  limits: Partial<MinMax>,
) => {
  const temporalColorRanges: ColoredRange[] = [];
  limits.min !== undefined &&
  limits.max !== undefined &&
  limits.min > limits.max
    ? (limits.min = limits.min + limits.max - (limits.max = limits.min))
    : colorPalette.forEach((colorRange, index) => {
        const newRange = fitColorRangeToMinMax(colorRange, limits);
        if (newRange) {
          temporalColorRanges.push(newRange);
        }
      });
  colorPalette.length = 0;
  if (temporalColorRanges.length === 0) {
    temporalColorRanges.push({
      from: limits.min !== undefined ? limits.min : -Infinity,
      to: limits.max !== undefined ? limits.max : Infinity,
    });
  }

  colorPalette.push(...temporalColorRanges);
};

/**
 * Generates a rect color scale for each series ID.
 *
 * @param seriesRect - Array of rect series with datapoints.
 * @param rectSeriesToMetadata - Metadata for each rect series.
 * @param seriesIdToValueScaleDomain - Mapping of series ID to their value scale domains.
 * @returns - A map of series IDs to their corresponding color scales.
 */
export function generateRectColorScaleBySeriesId(
  seriesRect: RectSeriesWithDatapoints[],
  rectSeriesToMetadata: RectSeriesToMetadata,
  seriesIdToValueScaleDomain: RectSeriesIdToValueScaleDomain,
) {
  const map = new Map<SeriesId, XYChartColorScale>();

  if (seriesIdToValueScaleDomain.size === 0) {
    return map;
  }

  seriesRect.forEach((series) => {
    const scaleDomain = safeGet(seriesIdToValueScaleDomain, series.id);
    const { colorPalette, valueMin, valueMax } = safeGet(
      rectSeriesToMetadata,
      series,
    );
    if (isMinMaxDomain(scaleDomain)) {
      if (isColoredRangeArray(colorPalette)) {
        fitColorRangePaletteToMinMax(colorPalette, {
          min: valueMin,
          max: valueMax,
        });

        const scale = buildThresholdScaleFromRanges(
          colorPalette,
          SCALE_FALLBACK_COLOR,
        );

        map.set(series.id, scale);
      } else {
        const scale = buildQuantizeScaleFromColorPalette(
          valueMin ?? scaleDomain.min,
          valueMax ?? scaleDomain.max,
          colorPalette,
        );
        map.set(series.id, scale);
      }
    } else if (isCategoricalDomain(scaleDomain)) {
      const categoricalColorPalette = !isColoredRangeArray(colorPalette)
        ? colorPalette
        : DEFAULT_COLOR_PALETTE_RECT;

      const scale = buildCategoricalColorScale(categoricalColorPalette, [
        ...scaleDomain.values(),
      ]);

      map.set(series.id, scale);
    }
  });

  return map;
}
